<template><div class="search-bar"><el-input v-model="keywordValue" clearable :placeholder="placeholder" @clear="emitSearch" @keyup.enter="emitSearch"><template #append><el-button @click="emitSearch">&#25628;&#32034;</el-button></template></el-input></div></template><script setup>import { computed } from 'vue'; const props = defineProps({ modelValue: { type: String, default: '' }, placeholder: { type: String, default: '\u8bf7\u8f93\u5165\u5173\u952e\u8bcd' } }); const emit = defineEmits(['update:modelValue','search']); const keywordValue = computed({ get: () => props.modelValue, set: (value) => emit('update:modelValue', value) }); const emitSearch = () => emit('search')</script><style scoped>.search-bar{width:100%}</style>
